INSERT INTO `Cartas` VALUES
(1,1,'Bugatti Chiron','Supercarro',1,'O Bugatti Chiron é um supercarro produzido pela fabricante francesa Bugatti. Ele é conhecido por sua velocidade impressionante e design luxuoso.'),
(2,1,'Fiat Uno','Popular',4,'O Fiat Uno é um compacto econômico e prático, ideal para uso urbano. Ele se destaca pelo baixo consumo, manutenção barata e simplicidade mecânica.'),
(3,1,'Volkswagen Gol','Popular',4,'O Volkswagen Gol é um dos carros mais populares do Brasil, conhecido pela robustez mecânica, desempenho acima da média entre os compactos e manutenção simples. '),
(4,1,'Ferrari SF90 Stradale','Supercarro',1,'Híbrido de altíssima performance com foco em aceleração e precisão.'),
(5,1,'McLaren P1','Supercarro',1,'Híbrido de produção limitada com foco em performance de pista.'),
(6,1,'Porsche 918 Spyder','Supercarro',1,'Híbrido de engenharia avançada com grande eficiência e potência.'),
(7,1,'Pagani Huayra R','Supercarro',1,'Supercarro artesanal com foco absoluto em leveza e velocidade.'),
(8,1,'Ferrari 812 Competizione','Supercarro',1,'Coupé de motor V12 com alta rotação e grande estabilidade.'),
(9,1,'Ford GT Mk IV','Supercarro',1,'Versão extrema com foco em desempenho e construção leve.'),
(10,1,'Lamborghini Aventador SVJ','Supercarro',1,'Coupé de motor V12 com alta potência e grande presença visual.'),
(11,1,'BMW M3 Competition','Esportivo',2,'Sedã de alta performance com foco em precisão e potência.'),
(12,1,'Audi RS5 Coupé','Esportivo',2,'Coupé esportivo com forte aceleração e dirigibilidade refinada.'),
(13,1,'Mercedes‑AMG C63 S','Esportivo',2,'Sedã esportivo com motor potente e comportamento agressivo.'),
(14,1,'Ford New Fiesta Titanium','Popular',3,'Hatch premium com boa dirigibilidade, acabamento superior e desempenho equilibrado.'),
(15,1,'Chevrolet Camaro SS','Muscle',2,'Cupê musculoso com grande torque e presença marcante.'),
(16,1,'Ford Mustang GT','Muscle',2,'Esportivo de tração traseira com forte aceleração e estilo clássico.'),
(17,1,'Volvo XC90 T8 Hybrid','SUV',2,'SUV híbrido com foco em conforto, tecnologia e desempenho equilibrado.'),
(18,1,'Toyota Supra GR','Esportivo',2,'Cupê esportivo com excelente equilíbrio entre potência e controle.'),
(19,1,'Porsche Macan GTS','SUV',2,'SUV compacto esportivo com aceleração forte e condução precisa.'),
(20,1,'Honda Civic EXL','Popular',3,'Sedã confortável com bom desempenho e eficiência.'),
(21,1,'Toyota Corolla GLi','Popular',3,'Modelo equilibrado com foco em economia e confiabilidade.'),
(22,1,'Volkswagen Polo MSI','Popular',3,'Hatch moderno com boa dirigibilidade e consumo eficiente.'),
(23,1,'Hyundai HB20 Premium 1.6','Popular',3,'Hatch urbano com desempenho ágil e bom pacote de equipamentos.'),
(24,1,'Chevrolet Onix Plus Premier','Popular',3,'Sedã compacto eficiente com bom espaço interno e tecnologia.'),
(25,1,'Renault Duster','SUV',3,'SUV robusto com boa altura e espaço interno.'),
(26,1,'Nissan Kicks','SUV',3,'SUV leve e econômico com foco em conforto urbano.'),
(27,1,'Lada Laika 2107','Popular',4,'Modelo simples e robusto, com construção tradicional e desempenho modesto.'),
(28,1,'Chevrolet Celta 1.0','Popular',4,'Hatch compacto básico com foco em economia e simplicidade.'),
(29,1,'Volkswagen Fusca 1600','Popular',4,'Modelo clássico com construção peculiar e desempenho limitado.'),
(30,1,'Chevrolet Classic 1.0','Popular',4,'Sedã compacto simples com boa economia e manutenção acessível.'),
(31,1,'Ford Ka 1.0','Popular',4,'Hatch compacto básico com dimensões reduzidas e desempenho modesto.'),
(32,1,'Chery QQ 1.0','Popular',4,'Subcompacto urbano com foco em baixo custo e simplicidade.');
